	.TITLE	CLAVIER;	--------------------------------------;		(C) 1986 - Daniel Roux;	--------------------------------------;	Source pour EPROM 2732 du processeur HD63P01	.PROC	M6801		; mmes instructions que le M6801; Principales adresses mmoires; -----------------------------REG	=	H'0000		; registres internesRAM	=	H'0080		; dbut de la RAM interneLRAM	=	H'0080		; lg de la RAM interneROM	=	H'F000		; dbut de l'EPROM 2732LROM	=	H'1000		; lg de l'EPROM 2732; Internal register area; ----------------------	.LOC	REGDDIR1:	.BLKB	1		; port1: directionDDIR2:	.BLKB	1		; port2: directionDATA1:	.BLKB	1		; port1: dataDATA2:	.BLKB	1		; port2: dataDDIR3:	.BLKB	1		; port3: directionDDIR4:	.BLKB	1		; port4: directionDATA3:	.BLKB	1		; port3: dataDATA4:	.BLKB	1		; port4: dataTIMER:	.BLKB	1		; timer: control and statusCOUNTH:	.BLKB	1		; counter (high)COUNTL:	.BLKB	1		; counter (low)COMPH:	.BLKB	1		; compare (high)COMPL:	.BLKB	1		; compare (low)CAPTH:	.BLKB	1		; capture (high)CAPTL:	.BLKB	1		; capture (low)CTRL3:	.BLKB	1		; port3: controlRATE:	.BLKB	1		; rate and modeTRSTA:	.BLKB	1		; transmit/receive statusRDATA:	.BLKB	1		; receive: dataTDATA:	.BLKB	1		; transmit: dataRAMCR:	.BLKB	1		; RAM control; Priphriques; -------------; Les [] indiquent l'tat de repos (inactif) !; N.C. = not connected; DATA1 bit0	-->	[1] data out; DATA1 bit1	-->	[1] data out; DATA1 bit2	-->	[1] data out; DATA1 bit3	-->	[1] data out; DATA1 bit4	-->	[1] data out; DATA1 bit5	-->	[1] data out; DATA1 bit6	-->	[1] data out; DATA1 bit7	-->	[1] data out; DATA2 bit0	<--	N.C.; DATA2 bit1	<--	N.C.; DATA2 bit2	<--	N.C.; DATA2 bit3	<--	N.C.; DATA2 bit4	-->	midi out; DATA3 bit0	<--	[0] p'tit bouton; DATA3 bit1	-->	[0] p'tite led; DATA3 bit2	<--	N.C.; DATA3 bit3	<--	N.C.; DATA3 bit4	<--	N.C.; DATA3 bit5	<--	N.C.; DATA3 bit6	<--	N.C.; DATA3 bit7	<--	N.C.; DATA4 bit0	<--	[1] data in; DATA4 bit1	<--	[1] data in; DATA4 bit2	<--	[1] data in; DATA4 bit3	<--	[1] data in; DATA4 bit4	<--	[1] data in; DATA4 bit5	<--	[1] data in; DATA4 bit6	<--	[1] data in; DATA4 bit7	<--	[1] data in; Variables; ---------	.LOC	RAMCLA1:	.BLKB	1		; tat du clavierCLA2:	.BLKB	1		; tat du clavierCLA3:	.BLKB	1		; tat du clavierCLA4:	.BLKB	1		; tat du clavierCLA5:	.BLKB	1		; tat du clavierCLA6:	.BLKB	1		; tat du clavierCLA7:	.BLKB	1		; tat du clavierLIMIT:	.BLKB	1CANB:	.BLKB	1CANH:	.BLKB	1OFBASB:	.BLKB	1OFBASH:	.BLKB	1OFCLA:	.BLKB	1OFNOTE:	.BLKB	1TOTO:	.BLKB	1; Dbut de l'EPROM 2732; ---------------------	.LOC	ROMSTART:	LOAD	SP,#RAM+LRAM-1	LOAD	IX,#TAINIT	CALL	INIPER	LOAD	A,#B'11111111	LOAD	CLA1,A	LOAD	CLA2,A	LOAD	CLA3,A	LOAD	CLA4,A	LOAD	CLA5,A	LOAD	CLA6,A	LOAD	CLA7,A	LOAD	A,#12*2	LOAD	LIMIT,A	LOAD	A,#H'90	LOAD	CANB,A	LOAD	CANH,A	LOAD	A,#12*3	LOAD	OFBASB,A	LOAD	OFBASH,A	LOAD	A,#0	LOAD	TOTO,ALOOP:	LOAD	A,DATA3	RRC	A		; p'tit bouton press ?	JUMP,CC 10$		; non => 10$				; oui =>	CALL	MODPAR		; moteur ...10$:	CALL	IFCLA	LOAD	A,TOTO	COMP	A,#0	JUMP,EQ 20$	CALL	LEDON	JUMP	LOOP20$:	CALL	LEDOFF	JUMP	LOOP;--------\\; MODPAR  >;========/; Paramtrise le clavier.; in	-; out	-; mod	toutMODPAR:	CALL	LEDON		; allume la LED	CALL	GETCAR		; A <-- touche presse	LOAD	IX,#OFBASB	COMP	A,#0	JUMP,EQ TON$	LOAD	IX,#OFBASH	COMP	A,#2	JUMP,EQ TON$	LOAD	IX,#CANB	COMP	A,#1	JUMP,EQ CAN$	LOAD	IX,#CANH	COMP	A,#3	JUMP,EQ CAN$	COMP	A,#4	JUMP,EQ LIMIT$	JUMP	EXIT$TON$:	CALL	GETCAR		; A <-- touche presse	ADD	A,#12	LOAD	(IX),A	JUMP	EXIT$CAN$:	CALL	GETCAR		; A <-- touche presse	LOAD	B,#H'90	COMP	A,#0		; do ?	JUMP,EQ CANX$	DEC	A		; noire ?	JUMP,EQ EXIT$	INC	B	DEC	A		; r ?	JUMP,EQ CANX$	DEC	A		; noire ?	JUMP,EQ EXIT$	INC	B	DEC	A		; mi ?	JUMP,EQ CANX$	INC	B	DEC	A		; fa ?	JUMP,EQ CANX$	DEC	A		; noire ?	JUMP,EQ EXIT$	INC	B	DEC	A		; sol ?	JUMP,EQ CANX$	DEC	A		; noire ?	JUMP,EQ EXIT$	INC	B	DEC	A		; la ?	JUMP,EQ CANX$	DEC	A		; noire ?	JUMP,EQ EXIT$	INC	B	DEC	A		; si ?	JUMP,EQ CANX$	INC	B	DEC	A		; do ?	JUMP,EQ CANX$	DEC	A		; noire ?	JUMP,EQ EXIT$	INC	B	DEC	A		; r ?	JUMP,EQ CANX$	DEC	A		; noire ?	JUMP,EQ EXIT$	INC	B	DEC	A		; mi ?	JUMP,EQ CANX$	INC	B	DEC	A		; fa ?	JUMP,EQ CANX$	DEC	A		; noire ?	JUMP,EQ EXIT$	INC	B	DEC	A		; sol ?	JUMP,EQ CANX$	DEC	A		; noire ?	JUMP,EQ EXIT$	INC	B	DEC	A		; la ?	JUMP,EQ CANX$	DEC	A		; noire ?	JUMP,EQ EXIT$	INC	B	DEC	A		; si ?	JUMP,EQ CANX$	INC	B	DEC	A		; do ?	JUMP,EQ CANX$	DEC	A		; noire ?	JUMP,EQ EXIT$	INC	B	DEC	A		; r ?	JUMP,EQ CANX$	JUMP	EXIT$CANX$:	LOAD	(IX),B	JUMP	EXIT$LIMIT$:	CALL	GETCAR		; A <-- touche presse	LOAD	LIMIT,A;	JUMP	EXIT$EXIT$:	CALL	LEDOFF		; teint la LED	RET;--------\\; IFCLA   >;========/; ; in	-; out	-; mod	FIFCLA:	PUSH	A	PUSH	B	PUSH	IX	LOAD	A,#0	LOAD	OFCLA,A	LOAD	IX,#CLA1	; IX <-- ^ancien tat	LOAD	B,#B'1111111010$:	LOAD	DATA1,B		; slectionne une colonne	CALL	BALCO	INC	IX		; IX <-- ^suivant	LOAD	A,OFCLA	ADD	A,#8	LOAD	OFCLA,A		; OFCLA <-- +8 notes	SETC	RLC	B	COMP	B,#B'01111111	JUMP,NE 10$	LOAD	A,#B'11111111	LOAD	DATA1,A	POP	IX	POP	B	POP	A	RET;--------\\; BALCO   >;--------/; ; in	IX	^tat; out	(IX)	nouvel tat; mod	FBALCO:	PUSH	A	PUSH	B	LOAD	A,#0	LOAD	OFNOTE,A	LOAD	A,DATA4		; A4 <-- lit une colonne	LOAD	B,A	XOR	A,(IX)	JUMP,EQ 90$	LOAD	(IX),B	CALL	TELEG	CALL	TELEG	CALL	TELEG	CALL	TELEG	CALL	TELEG	CALL	TELEG	CALL	TELEG	CALL	TELEG90$:	POP	B	POP	A	RET;--------\\; TELEG   >;--------/; ; in	A	changements;	B	tat; out	A	changements;	B	tat; mod	F,A,BTELEG:	RRC	A	JUMP,CC	90$	PUSH	A	LOAD	A,OFCLA	ADD	A,OFNOTE	COMP	A,LIMIT	JUMP,HS 10$				; moiti du bas =>	LOAD	A,CANB	CALL	PUTMIDI	LOAD	A,OFBASB	ADD	A,OFCLA	ADD	A,OFNOTE	CALL	PUTMIDI	JUMP	20$10$:				; moiti du haut =>	LOAD	A,CANH	CALL	PUTMIDI	LOAD	A,OFBASH	ADD	A,OFCLA	ADD	A,OFNOTE	CALL	PUTMIDI20$:	LOAD	A,B	RRC	A	JUMP,CS 40$				; press =>	LOAD	A,#64	CALL	PUTMIDI	LOAD	A,TOTO	INC	A	LOAD	TOTO,A	JUMP	60$40$:				; relch =>	LOAD	A,#0	CALL	PUTMIDI	LOAD	A,TOTO	DEC	A	LOAD	TOTO,A60$:	POP	A90$:	RRC	B	INC	OFNOTE	RET;--------\\; PUTMIDI >;========/; Envoie un byte sur MIDI.; in	A	byte  envoyer; out	-; mod	FPUTMIDI:	PUSH	B10$:	LOAD	B,TRSTA	RLC	B	RLC	B	RLC	B	JUMP,CC 10$		; transmit data ready ?	LOAD	TDATA,A	POP	B	RET;--------\\; LEDON   >;========/; Allume la p'tite lampe.; in	-; out	-; mod	FLEDON:	PUSH	A	LOAD	A,#B'00000010	LOAD	DATA3,A	POP	A	RET;--------\\; LEDOFF  >;========/; Eteint la p'tite lampe.; in	-; out	-; mod	FLEDOFF:	PUSH	A	LOAD	A,#B'00000000	LOAD	DATA3,A	POP	A	RET;--------\\; GETCAR  >;========/; Attend une touche du clavier.; in	-; out	A	touche presse; mod	F,AGETCAR:	PUSH	B10$:	CALL	BALCLA		; A <-- touche presse	COMP	A,#0		; une touche presse ?	JUMP,EQ 10$		; non => 10$	LOAD	B,A		; B <-- touche presse20$:	CALL	BALCLA		; A <-- touche presse	COMP	A,#0		; une touche presse ?	JUMP,NE 20$		; oui => 20$	LOAD	A,B		; A <-- touche presse (1..n)	DEC	A		; A <-- touche presse (0..n)	POP	B	RET;--------\\; BALCLA  >;========/; Balaie le clavier.; in	-; out	A	touche presse +1 (0 si rien); mod	F,ABALCLA:	PUSH	B	PUSH	IX	LOAD	IX,#0	LOAD	B,#B'1111111010$:	LOAD	DATA1,B		; slectionne une colonne	LOAD	A,DATA4		; A <-- lit une ligne	INC	IX	RLC	A	JUMP,CC 50$	INC	IX	RLC	A	JUMP,CC 50$	INC	IX	RLC	A	JUMP,CC 50$	INC	IX	RLC	A	JUMP,CC 50$	INC	IX	RLC	A	JUMP,CC 50$	INC	IX	RLC	A	JUMP,CC 50$	INC	IX	RLC	A	JUMP,CC 50$	INC	IX	RLC	A	JUMP,CC 50$	SETC	RLC	B	COMP	B,#B'01111111	JUMP,NE 10$	LOAD	IX,#050$:	PUSH	IX	INC	SP	POP	A		; A <-- IX	POP	IX	POP	B	RET; Initialisation; --------------;--------\\; INIPER  >;========/; in	IX	^table; out	-; mod	F,A,B,IXINIPER:10$:	LOAD	B,(IX)+0	; B <-- adresse	COMP	B,#-1	JUMP,EQ 90$	LOAD	A,(IX)+1	; A <-- data	PUSH	IX	LOAD	IX,#REG	ADD	IX,B		; IX <-- adresse	LOAD	(IX),A		; (adresse) <-- data	POP	IX	INC	IX	INC	IX	JUMP	10$90$:	RET; Dans le deuxime byte: 0=input 1=outputTAINIT:	.B	DDIR1,B'11111111	; clavier out	.B	DDIR2,B'00010100	; srie	.B	DDIR3,B'00000010	; led + bouton	.B	DDIR4,B'00000000	; clavier in	.B	DATA1,B'11111111	; data clavier out	.B	DATA3,B'00000000	; led teinte	.B	RATE,B'00000100		; internal clock + xtal /16	.B	TRSTA,B'00000010	; transmit enable	.B	-1			; fin de la table; Vecteurs  la fin de la mmoire; -------------------------------	.LOC	ROM+LROM-H'10	.W	START		; SCI	.W	START		; TOF	.W	START		; OCF	.W	START		; ICF	.W	START		; IRQ	.W	START		; SWI	.W	START		; NMI	.W	START		; RESET	.END	START